import React, { useState, useEffect, useRef } from "react";
import RecommendCard from "../components/RecommendCard";
import './RecommendCard.css';export default function Recommend() {
  const [query, setQuery] = useState("");
  const [titles, setTitles] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [showDrop, setShowDrop] = useState(false);
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const inputRef = useRef(null);

  /* Load all titles for autocomplete */
  useEffect(() => {
    fetch("http://127.0.0.1:5000/api/titles")
      .then((r) => r.json())
      .then(setTitles)
      .catch(() => {});
  }, []);

  /* Filter suggestions */
  useEffect(() => {
    if (query.length < 2) {
      setFiltered([]);
      return;
    }
    const q = query.toLowerCase();
    setFiltered(titles.filter((t) => t.toLowerCase().includes(q)).slice(0, 8));
  }, [query, titles]);

  const selectTitle = (t) => {
    setQuery(t);
    setFiltered([]);
    setShowDrop(false);
  };

  const handleSubmit = async (e) => {
    e?.preventDefault();
    if (!query.trim()) return;
    setLoading(true);
    setError("");
    setResults(null);

    try {
      const res = await fetch("http://127.0.0.1:5000/api/recommend", {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ book: query }),
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.error || "Something went wrong.");
      } else {
        setResults(data);
      }
    } catch {
      setError("Could not connect to the server. Is Flask running?");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="recommend-page">
      {/* ── Banner ── */}
      <section className="rec-banner">
        <div className="rec-banner__bg">
          <div className="rec-banner__blob" />
        </div>
        <div className="container rec-banner__content">
          <span className="rec-eyebrow">Collaborative Filtering</span>
          <h1>
            Find Books <em>Like This One</em>
          </h1>
          <p>
            Enter any book title and we'll surface four similar reads based on
            shared reader preferences.
          </p>

          {/* Search form */}
          <div className="rec-search-wrap">
            <form className="rec-search" onSubmit={handleSubmit}>
              <div className="rec-search__input-wrap" ref={inputRef}>
                <span className="rec-search__icon">🔍</span>
                <input
                  type="text"
                  className="rec-search__input"
                  placeholder="e.g. Harry Potter and the Chamber of Secrets"
                  value={query}
                  onChange={(e) => {
                    setQuery(e.target.value);
                    setShowDrop(true);
                  }}
                  onFocus={() => setShowDrop(true)}
                  onBlur={() => setTimeout(() => setShowDrop(false), 180)}
                  autoComplete="off"
                />
                {query && (
                  <button
                    type="button"
                    className="rec-search__clear"
                    onClick={() => {
                      setQuery("");
                      setResults(null);
                      setError("");
                    }}
                  >
                    ✕
                  </button>
                )}

                {/* Dropdown */}
                {showDrop && filtered.length > 0 && (
                  <ul className="rec-dropdown">
                    {filtered.map((t) => (
                      <li key={t} onMouseDown={() => selectTitle(t)}>
                        <span className="rec-dropdown__icon">📖</span>
                        {t}
                      </li>
                    ))}
                  </ul>
                )}
              </div>
              <button
                type="submit"
                className="rec-search__btn"
                disabled={loading}
              >
                {loading ? <span className="rec-spinner" /> : "Recommend"}
              </button>
            </form>
          </div>
        </div>
      </section>

      {/* ── Results ── */}
      <section className="rec-results container">
        {error && (
          <div className="rec-error fade-up">
            <span>⚠️</span> {error}
          </div>
        )}

        {loading && (
          <div className="rec-loading">
            <div className="rec-grid">
              {Array(4)
                .fill(0)
                .map((_, i) => (
                  <div key={i} className="rec-card-skeleton">
                    <div
                      className="skeleton"
                      style={{ height: 220, borderRadius: 12 }}
                    />
                    <div style={{ padding: "16px 0" }}>
                      <div
                        className="skeleton"
                        style={{ height: 14, marginBottom: 8, borderRadius: 6 }}
                      />
                      <div
                        className="skeleton"
                        style={{
                          height: 18,
                          marginBottom: 12,
                          borderRadius: 6,
                        }}
                      />
                      <div
                        className="skeleton"
                        style={{ height: 8, borderRadius: 99 }}
                      />
                    </div>
                  </div>
                ))}
            </div>
          </div>
        )}

        {results && !loading && (
          <>
            <div className="rec-results-header">
              <h2>Recommended Books</h2>
              <p>
                Based on readers who enjoyed <strong>"{query}"</strong>
              </p>
            </div>
            <div className="rec-grid">
              {results.map((book, i) => (
                <RecommendCard key={i} book={book} delay={i * 100} />
              ))}
            </div>
          </>
        )}

        {/* Placeholder when nothing searched yet */}
        {!results && !loading && !error && (
          <div className="rec-placeholder fade-up">
            <div className="rec-placeholder__icon">📚</div>
            <h3>Start by searching for a book</h3>
            <p>Type a title above and we'll find similar reads you'll love.</p>
          </div>
        )}
      </section>
    </div>
  );
}
